16	//     вҶ’ 401 { error: 'UNAUTHORIZED' }
17	//     вҶ’ 403 { error: 'FORBIDDEN' }       // non-creator role
18	//     вҶ’ 404 { error: 'LISTING_NOT_FOUND' } // also covers draft/archived listings
19	//     вҶ’ 500 { error: 'SERVER_MISCONFIGURED' | 'DB_ERROR' }
