318	  if (conditionsRes.error) {
319	    console.error("listing_conditions lookup failed", conditionsRes.error);
320	    return jsonResponse(500, { error: "DB_ERROR" });
321	  }
322	  if (videosRes.error) {
323	    console.error("sample_videos lookup failed", videosRes.error);
324	    return jsonResponse(500, { error: "DB_ERROR" });
325	  }
326	  if (profileRes.error) {
327	    console.error("creator_profiles lookup failed", profileRes.error);
328	    return jsonResponse(500, { error: "DB_ERROR" });
329	  }
330	  if (appsRes.error) {
331	    console.error("applications lookup failed", appsRes.error);
332	    return jsonResponse(500, { error: "DB_ERROR" });
333	  }
334	
335	  const conditions = (conditionsRes.data ?? []) as ConditionRow[];
336	
337	  // Creator profile is created by the signup flow (US-014) so every
338	  // creator JWT should have one, but treat a missing row as fully-null
339	  // metrics вҖ” fail-closed on every numeric threshold.
340	  const metrics: CreatorProfileRow = profileRes.data ?? {
341	    tiktok_follower_count: null,
342	    tiktok_avg_views_last_10: null,
343	    tiktok_total_likes: null,
344	    tiktok_video_count: null,
345	    tiktok_is_verified: null,
346	    instagram_follower_count: null,
347	    instagram_avg_views_last_10: null,
348	    instagram_media_count: null,
